# tests/architecture/test_adapter_isolation.py
# Verifies: no module outside src/adapters/ imports the anthropic SDK directly.

import ast, pathlib, pytest

ADAPTER_DIR   = pathlib.Path("src/adapters/")
SOURCE_ROOT   = pathlib.Path("src/")
FORBIDDEN_IMPORTS = {"anthropic", "openai"}   # LLM SDK packages

def get_imports(path: pathlib.Path) -> set[str]:
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        return set()
    imports = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            imports.update(alias.name.split(".")[0] for alias in node.names)
        elif isinstance(node, ast.ImportFrom) and node.module:
            imports.add(node.module.split(".")[0])
    return imports

def non_adapter_python_files():
    for path in SOURCE_ROOT.rglob("*.py"):
        if not path.is_relative_to(ADAPTER_DIR):
            yield path

@pytest.mark.parametrize("source_file", list(non_adapter_python_files()))
def test_no_direct_llm_sdk_import(source_file):
    imports = get_imports(source_file)
    violations = imports & FORBIDDEN_IMPORTS
    assert not violations, (
        f"{source_file} imports {violations} directly. "
        "All LLM SDK usage must go through src/adapters/. "
        "Import the adapter interface, not the SDK."
    )

# tests/architecture/test_domain_purity.py
# Verifies: domain layer classes have no LLM-related method signatures.
# A domain class that calls an LLM directly is a design violation.

import ast, pathlib, pytest

DOMAIN_DIR = pathlib.Path("src/domain/")
LLM_MARKERS = {"messages", "max_tokens", "anthropic", "client.create"}

def get_method_names(path: pathlib.Path) -> list[str]:
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        return []
    names = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            names.append(node.name)
            # Also check argument names
            for arg in node.args.args:
                if any(m in arg.arg for m in ("messages", "max_tokens")):
                    names.append(f"{node.name}:{arg.arg}")
    return names

@pytest.mark.parametrize("domain_file", list(DOMAIN_DIR.rglob("*.py")))
def test_domain_has_no_llm_signatures(domain_file):
    source = domain_file.read_text()
    # Check for tell-tale LLM patterns in domain files
    for marker in LLM_MARKERS:
        # Allow imports from adapters package (dependency injection)
        if marker in source and "from src.adapters" not in source:
            if f'"{marker}"' in source or f"'{marker}'" in source:
                pytest.fail(
                    f"{domain_file} contains LLM marker '{marker}'. "
                    "Domain classes must not call LLM APIs. "
                    "Inject the adapter via the constructor."
                )

# tests/architecture/test_prompt_hygiene.py
import ast, pathlib, re, yaml, pytest

SOURCE_ROOT = pathlib.Path("src/")
PROMPTS_DIR = pathlib.Path("prompts/")

# Pattern that detects an inline system prompt (multi-line string containing
# "You are" or similar LLM preamble directly in Python source)
INLINE_PROMPT_RE = re.compile(
    r'("""[^"]{50,}(You are|Act as|Your task|Always respond)[^"]{20,}"""'
    r'|'''[^']{50,}(You are|Act as|Your task|Always respond)[^']{20,}''')',
    re.DOTALL
)

@pytest.mark.parametrize("source_file", list(SOURCE_ROOT.rglob("*.py")))
def test_no_inline_prompt(source_file):
    source = source_file.read_text()
    match = INLINE_PROMPT_RE.search(source)
    assert not match, (
        f"{source_file} contains what appears to be an inline system prompt. "
        "All prompts must be stored as YAML files in prompts/ and loaded "
        "via load_prompt(). Inline prompts cannot be linted, versioned, or reviewed."
    )

def prompt_yaml_files():
    return list(PROMPTS_DIR.glob("**/*.yaml"))

@pytest.mark.parametrize("prompt_file", prompt_yaml_files())
def test_prompt_has_safety_baseline(prompt_file):
    data = yaml.safe_load(prompt_file.read_text())
    system = data.get("system", "")
    assert re.search(r"safety baseline v\d+\.\d+", system, re.IGNORECASE), (
        f"{prompt_file}: missing safety baseline. "
        "Add the safety baseline block from prompts/partials/safety_baseline_v2.1.txt"
    )

@pytest.mark.parametrize("prompt_file", prompt_yaml_files())
def test_prompt_version_is_semver(prompt_file):
    data = yaml.safe_load(prompt_file.read_text())
    version = data.get("version", "")
    assert re.match(r"^\d+\.\d+\.\d+$", version), (
        f"{prompt_file}: version '{version}' is not valid semver (X.Y.Z). "
    )

@pytest.mark.parametrize("prompt_file", prompt_yaml_files())
def test_user_input_is_delimited(prompt_file):
    data = yaml.safe_load(prompt_file.read_text())
    injection_surface = data.get("injection_surface", "none")
    if injection_surface == "none":
        return  # no user input — nothing to check
    system = data.get("system", "")
    for field in (injection_surface if isinstance(injection_surface, list) else [injection_surface]):
        assert f"<{field}>" in system, (
            f"{prompt_file}: injection_surface declares '{field}' "
            f"but system prompt does not wrap it in <{field}>...</{field}> XML tags."
        )

# tests/architecture/test_cost_governance.py
import ast, pathlib, yaml, pytest

SOURCE_ROOT = pathlib.Path("src/")
ALERTS_FILE = pathlib.Path("config/alerts.yaml")

class LLMCallVisitor(ast.NodeVisitor):
    """Finds calls to client.messages.create and checks for max_tokens arg."""
    def __init__(self):
        self.missing_max_tokens = []

    def visit_Call(self, node):
        # Detect: anything.messages.create(...)
        if (isinstance(node.func, ast.Attribute)
                and node.func.attr == "create"
                and isinstance(node.func.value, ast.Attribute)
                and node.func.value.attr == "messages"):
            keywords = {kw.arg for kw in node.keywords}
            if "max_tokens" not in keywords:
                self.missing_max_tokens.append(ast.get_lineno(node))
        self.generic_visit(node)

@pytest.mark.parametrize("source_file", list(SOURCE_ROOT.rglob("*.py")))
def test_all_llm_calls_have_max_tokens(source_file):
    try:
        tree = ast.parse(source_file.read_text())
    except SyntaxError:
        return
    visitor = LLMCallVisitor()
    visitor.visit(tree)
    assert not visitor.missing_max_tokens, (
        f"{source_file} has LLM calls without max_tokens at lines: "
        f"{visitor.missing_max_tokens}. "
        "Every LLM call must set max_tokens explicitly to prevent runaway token usage."
    )

def test_cost_alert_configured():
    """The alerting config must contain a cost spike alert for the LLM feature."""
    if not ALERTS_FILE.exists():
        pytest.skip("No alerts config file found")

    alerts = yaml.safe_load(ALERTS_FILE.read_text())
    alert_names = [a.get("name", "") for a in alerts.get("alerts", [])]
    cost_alerts = [n for n in alert_names if "cost" in n.lower() and "llm" in n.lower()]

    assert cost_alerts, (
        f"No LLM cost alert found in {ALERTS_FILE}. "
        "Add an alert that fires when LLM cost exceeds 2× the 7-day average. "
        "See docs/alerting-requirements.md for the required alert format."
    )
